const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant = 'primary', size = 'md', isLoading, asChild = false, children, ...props }, ref) => {
    // Base styles
    const baseStyles = cn(
      "inline-flex items-center justify-center rounded-xl text-sm font-semibold transition-all duration-300",
      "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-purple-400 focus-visible:ring-offset-2 focus-visible:ring-offset-gray-900",
      "disabled:pointer-events-none disabled:opacity-50",
      !props.disabled && !isLoading && "hover:scale-105 active:scale-95"
    )

    // Variants with Aura Elite gradients
    const variants = {
      primary: cn(AURA_ELITE.gradients.primary, AURA_ELITE.shadows.md, "text-white"),
      secondary: cn(AURA_ELITE.gradients.secondary, AURA_ELITE.shadows.md, "text-white"),
      success: cn(AURA_ELITE.gradients.success, AURA_ELITE.shadows.sm, "text-white"),
      danger: cn(AURA_ELITE.gradients.danger, AURA_ELITE.shadows.sm, "text-white"),
      outline: "border border-white/20 bg-transparent hover:bg-white/5 text-white/80",
      ghost: "hover:bg-white/5 text-white/80",
    }

    // Sizes
    const sizes = {
      sm: "h-8 px-4 text-xs",
      md: "h-10 px-6 py-2",
      lg: "h-12 px-8 text-base",
      icon: "h-10 w-10",
    }

    const Comp = asChild ? Slot : "button"

    if (asChild) {
      return (
        <Slot
          className={cn(baseStyles, variants[variant], sizes[size], className)}
          ref={ref}
          {...props}
        >
          {children}
        </Slot>
      )
    }

    return (
      <button
        className={cn(baseStyles, variants[variant], sizes[size], className)}
        ref={ref}
        disabled={isLoading || props.disabled}
        {...props}
      >
        {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
        {children}
      </button>
    )
  }
)
Button.displayName = "Button"

export { Button }

import React from "react"
import {
  ColumnDef,
  flexRender,
  getCoreRowModel,
  useReactTable,
  getPaginationRowModel,
  SortingState,
  getSortedRowModel,
  OnChangeFn,
} from "@tanstack/react-table"
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "./table" // We need to create this primitive wrapper first or just inline it
import { Button } from "./Button"
import { ChevronLeft, ChevronRight, Loader2 } from "lucide-react"
import { cn } from "../../lib/utils"

// Since I haven't created the Table primitive components (shadcn/ui style),
// I will create them inline or better yet, create a separate file for them first
// to keep it clean. But for now, let's implement the logic in DataTable and
// standard HTML table elements with Tailwind classes matching Aura Elite.

interface DataTableProps<TData, TValue> {
  columns: ColumnDef<TData, TValue>[]
  data: TData[]
  pageCount: number
  pageIndex: number
  pageSize: number
  onPaginationChange: (pageIndex: number, pageSize: number) => void
  onSortingChange?: OnChangeFn<SortingState>
  sorting?: SortingState
  isLoading?: boolean
}

export function DataTable<TData, TValue>({
  columns,
  data,
  pageCount,
  pageIndex,
  pageSize,
  onPaginationChange,
  onSortingChange,
  sorting,
  isLoading,
}: DataTableProps<TData, TValue>) {
  const table = useReactTable({
    data,
    columns,
    getCoreRowModel: getCoreRowModel(),
    manualPagination: true,
    pageCount: pageCount,
    state: {
      pagination: {
        pageIndex,
        pageSize,
      },
      sorting,
    },
    onPaginationChange: (updater) => {
        if (typeof updater === 'function') {
            const newState = updater({ pageIndex, pageSize });
            onPaginationChange(newState.pageIndex, newState.pageSize);
        } else {
            onPaginationChange(updater.pageIndex, updater.pageSize);
        }
    },
    onSortingChange,
    manualSorting: true,
  })

  return (
    <div className="space-y-4">
      <div className="rounded-xl border border-white/20 dark:border-white/5 overflow-hidden bg-white/50 dark:bg-zinc-900/40 backdrop-blur-sm">
        <div className="relative w-full overflow-auto">
          <table className="w-full caption-bottom text-sm text-left">
            <thead className="[&_tr]:border-b border-white/10 dark:border-white/5">
              <tr className="border-b transition-colors hover:bg-white/5 data-[state=selected]:bg-white/5">
                {table.getHeaderGroups().map((headerGroup) => (
                  <React.Fragment key={headerGroup.id}>
                    {headerGroup.headers.map((header) => {
                      return (
                        <th
                          key={header.id}
                          className="h-12 px-4 align-middle font-medium text-slate-500 dark:text-slate-400 [&:has([role=checkbox])]:pr-0 cursor-pointer select-none hover:text-slate-900 dark:hover:text-slate-200"
                          onClick={header.column.getToggleSortingHandler()}
                        >
                          {header.isPlaceholder
                            ? null
                            : flexRender(
                                header.column.columnDef.header,
                                header.getContext()
                              )}
                        </th>
                      )
                    })}
                  </React.Fragment>
                ))}
              </tr>
            </thead>
            <tbody className="[&_tr:last-child]:border-0">
              {isLoading ? (
                <tr className="border-b border-white/10 dark:border-white/5">
                  <td
                    colSpan={columns.length}
                    className="h-24 text-center"
                  >
                    <div className="flex items-center justify-center gap-2 text-slate-500">
                        <Loader2 className="w-4 h-4 animate-spin" />
                        Loading data...
                    </div>
                  </td>
                </tr>
              ) : table.getRowModel().rows?.length ? (
                table.getRowModel().rows.map((row) => (
                  <tr
                    key={row.id}
                    data-state={row.getIsSelected() && "selected"}
                    className="border-b border-white/10 dark:border-white/5 transition-colors hover:bg-white/40 dark:hover:bg-white/5 data-[state=selected]:bg-white/10"
                  >
                    {row.getVisibleCells().map((cell) => (
                      <td
                        key={cell.id}
                        className="p-4 align-middle [&:has([role=checkbox])]:pr-0 text-slate-700 dark:text-slate-300"
                      >
                        {flexRender(
                          cell.column.columnDef.cell,
                          cell.getContext()
                        )}
                      </td>
                    ))}
                  </tr>
                ))
              ) : (
                <tr>
                  <td
                    colSpan={columns.length}
                    className="h-24 text-center text-slate-500 dark:text-slate-400"
                  >
                    No results.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="flex items-center justify-between px-2">
        <div className="text-sm text-slate-500 dark:text-slate-400">
           Page {pageIndex + 1} of {pageCount > 0 ? pageCount : 1}
        </div>
        <div className="flex items-center space-x-2">
          <Button
            variant="outline"
            size="sm"
            onClick={() => table.previousPage()}
            disabled={!table.getCanPreviousPage() || isLoading}
          >
            <ChevronLeft className="h-4 w-4" />
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={() => table.nextPage()}
            disabled={!table.getCanNextPage() || isLoading}
          >
            <ChevronRight className="h-4 w-4" />
          </Button>
        </div>
      </div>
    </div>
  )
}

import { ReactNode } from 'react'
