                      </div>
                       <div>
                          <p className="text-sm text-slate-500">Số điện thoại</p>
                          <p className="font-medium">{order.customer?.phone}</p>
                      </div>
                       <div>
                          <p className="text-sm text-slate-500">Địa chỉ</p>
