import { create } from 'zustand';
import { Session, User } from '@supabase/supabase-js';
import { supabase } from '../lib/supabase';

interface AuthState {
  session: Session | null;
  user: User | null;
  isLoading: boolean;
  isFounder: boolean;
  initialize: () => Promise<void>;
  signIn: () => Promise<void>;
  signOut: () => Promise<void>;
}

export const useAuthStore = create<AuthState>((set, get) => ({
  session: null,
  user: null,
  isLoading: true,
  isFounder: false,

  initialize: async () => {
    set({ isLoading: true });
    try {
      // Get initial session
      const { data: { session } } = await supabase.auth.getSession();

      if (session) {
        const user = session.user;
        // Check role in metadata
        const isFounder = user.app_metadata?.role === 'founder' || user.user_metadata?.role === 'founder';

        // If not found in metadata, could check profiles table here if needed
        // For now, assume metadata is populated correctly

        set({ session, user, isFounder });
      } else {
        set({ session: null, user: null, isFounder: false });
      }

      // Listen for changes
      supabase.auth.onAuthStateChange((_event, session) => {
        if (session) {
           const user = session.user;
           const isFounder = user.app_metadata?.role === 'founder' || user.user_metadata?.role === 'founder';
           set({ session, user, isFounder, isLoading: false });
        } else {
           set({ session: null, user: null, isFounder: false, isLoading: false });
        }
      });

    } catch (error) {
      console.error('Auth initialization failed:', error);
    } finally {
      set({ isLoading: false });
    }
  },

  signIn: async () => {
     // For now we might redirect to main app login or implement email login
     // Since this is admin panel, let's assume we want direct login here
     // or maybe we rely on shared session?
     // The plan says "Create Login Page".
  },

  signOut: async () => {
    await supabase.auth.signOut();
    set({ session: null, user: null, isFounder: false });
  },
}));

/**
 * CSV Export Utilities
 * Generate and download CSV files from data
 */

export interface CSVColumn<T = any> {
  key: string;
  header: string;
  formatter?: (value: unknown) => string;
}

/**
 * Convert data to CSV format
 */
export function convertToCSV<T extends Record<string, any>>(data: T[], columns: CSVColumn<T>[]): string {
  // Create header row
  const headers = columns.map(col => col.header).join(',');

  // Create data rows
  const rows = data.map(item => {
    return columns.map(col => {
      let value = item[col.key];

      // Apply formatter if provided
      if (col.formatter) {
        value = col.formatter(value);
      }

      // Handle null/undefined
      if (value === null || value === undefined) {
        value = '';
      }

      // Convert to string and escape quotes
      const stringValue = String(value).replace(/"/g, '""');

      // Wrap in quotes if contains comma, newline, or quotes
      if (stringValue.includes(',') || stringValue.includes('\n') || stringValue.includes('"')) {
        return `"${stringValue}"`;
      }

      return stringValue;
    }).join(',');
  });

  return [headers, ...rows].join('\n');
}

/**
 * Download CSV file
 */
export function downloadCSV(csv: string, filename: string): void {
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const link = document.createElement('a');

  if (link.download !== undefined) {
    // Create a link to the file
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }
}

/**
 * Export data to CSV and download
 */
export function exportToCSV<T extends Record<string, any>>(data: T[], columns: CSVColumn<T>[], filename: string): void {
  const csv = convertToCSV(data, columns);
  downloadCSV(csv, filename);
}

