    const missingInEn = viKeys.filter(k => !enSet.has(k));
    const missingInVi = enKeys.filter(k => !viSet.has(k));

    const issues: FixReport[] = [];

    if (missingInEn.length > 0) {
      issues.push({
        file: enPath,
        fixes: [`Missing keys: ${missingInEn.join(', ')}`],
        errors: []
