async function main() {
    console.log("🕵️  Verifying Order Mapping Logic (Multi-Tab)...");

    // 1. Create User
    const email = `mapping_test_${Date.now()}@example.com`;
    const { data: { user }, error: userError } = await supabase.auth.admin.createUser({
        email,
