        user_id: user?.id,
        amount: 2000000, // 2M VND
        type: 'Direct Sale',
        status: 'completed',
        currency: 'VND'
    }).select().single();

    if (orderError) { console.error(orderError); return; }
    console.log(`✅ Order Created in 'transactions' table.`);

