    console.log(`\n3️⃣  Checking 'agent_jobs' for mapping...`);
    let job = null;
    for (let i = 0; i < 10; i++) {
        await new Promise(r => setTimeout(r, 1000));
        const { data } = await supabase.from('agent_jobs').select('*').contains('payload', { transaction_id: orderId });
        if (data && data.length > 0) {
