    console.log(`   │  👤 User: ${user?.email}`);
    console.log(`   │`);
    console.log(`   ▼`);
    console.log(`🐝 Agent Job: [${job.id}]`);
    console.log(`   │  ⚙️  Action: process_reward`);
    console.log(`   │  🤖 Agent: The Bee`);
    console.log(`   │`);
    console.log(`   ▼`);

