async function main() {
    console.log("🕵️  Bắt đầu kiểm tra hệ thống Production...");

    // 1. Tạo User Test
    const email = `test_probe_${Date.now()}@example.com`;
    console.log(`\n1️⃣  Tạo User Test: ${email}`);
    if (!process.env.TEST_USER_PASSWORD) {
