              {item.highlight && (
                <motion.div
                  className="absolute -top-1 -right-1 w-2 h-2 bg-emerald-500 rounded-full"
                  animate={{ scale: [1, 1.3, 1] }}
                  transition={{ duration: 2, repeat: Infinity }}
                />
              )}
            </Link>
          ) : (
            <button
              className={`
                flex items-center gap-1.5 px-4 py-2 text-sm font-medium rounded-xl
                transition-all duration-300
                ${activeDropdown === item.label
                  ? 'text-white bg-zinc-800'
                  : 'text-zinc-400 hover:text-white hover:bg-zinc-800/50'}
              `}
            >
              {item.label}
              {item.children && (
                <motion.div
                  animate={{ rotate: activeDropdown === item.label ? 180 : 0 }}
                  transition={{ duration: 0.2 }}
                >
                  <ChevronDown className="w-4 h-4" />
                </motion.div>
              )}
            </button>
          )}

          {/* Premium Dropdown */}
          <AnimatePresence>
            {item.children && activeDropdown === item.label && (
              <motion.div
                initial={{ opacity: 0, y: 10, scale: 0.95 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                exit={{ opacity: 0, y: 10, scale: 0.95 }}
                transition={{ duration: 0.2, ease: [0.16, 1, 0.3, 1] }}
                className="absolute top-full left-0 pt-3 w-80"
              >
                <div className="relative bg-zinc-900/95 backdrop-blur-2xl border border-zinc-700/50 rounded-2xl p-2 shadow-2xl shadow-black/40">
                  {/* Top accent */}
                  <div className="absolute top-0 left-4 right-4 h-px bg-gradient-to-r from-transparent via-emerald-500/50 to-transparent" />

                  {item.children.map((child) => (
                    <Link
                      key={child.label}
                      to={child.href}
                      className={`
                        flex items-start gap-4 p-4 rounded-xl transition-all duration-200 group
                        ${location.pathname === child.href
                          ? 'bg-emerald-500/10'
                          : 'hover:bg-zinc-800/50'
                        }
                      `}
                    >
                      <div className={`
                        w-12 h-12 rounded-xl flex items-center justify-center transition-all duration-300
                        ${location.pathname === child.href
                          ? 'bg-gradient-to-br from-emerald-500 to-cyan-500 text-black'
                          : 'bg-zinc-800 border border-zinc-700 text-emerald-400 group-hover:bg-emerald-500/20 group-hover:border-emerald-500/30'
                        }
                      `}>
                        {child.icon}
                      </div>
                      <div className="flex-1">
                        <div className="flex items-center gap-2">
                          <span className={`
                            text-sm font-semibold transition-colors
                            ${location.pathname === child.href ? 'text-emerald-400' : 'text-white group-hover:text-emerald-400'}
                          `}>
                            {child.label}
                          </span>
                          {child.badge && (
                            <span className={`
                              px-2 py-0.5 text-[10px] font-bold rounded-full
                              ${child.badgeColor
                                ? `bg-gradient-to-r ${child.badgeColor} text-white`
                                : 'bg-zinc-700 text-zinc-300'
                              }
                            `}>
                              {child.badge}
                            </span>
                          )}
                        </div>
                        <div className="text-xs text-zinc-500 mt-1 leading-relaxed">
                          {child.description}
                        </div>
                      </div>
                      <ChevronRight className="w-4 h-4 text-zinc-600 group-hover:text-emerald-400 group-hover:translate-x-1 transition-all" />
                    </Link>
                  ))}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      ))}
    </nav>
  );
}

import { uiLogger } from '@/utils/logger';

import React, { useState } from 'react';
import { Product } from '../types';
import { ShoppingBag, Share2, Loader2, CheckCircle, Eye } from 'lucide-react';
import { formatVND } from '../utils/format';
import { useStore } from '../store';
import { useNavigate } from 'react-router-dom';
import { useTranslation } from '@/hooks';
import { useToast } from '@/components/ui/Toast';

interface Props {
  product: Product;
}

const ProductCard: React.FC<Props> = ({ product }) => {
    const { t } = useTranslation();
  const { simulateOrder } = useStore();
  const navigate = useNavigate();
  const { showToast } = useToast();
  const [isBuying, setIsBuying] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);

  const handleBuy = async (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsBuying(true);
    try {
      await new Promise(r => setTimeout(r, 800));
      await simulateOrder(product.id);
      setShowSuccess(true);
      setTimeout(() => setShowSuccess(false), 2000);
    } finally {
      setIsBuying(false);
    }
  };

  const handleShare = async (e: React.MouseEvent) => {
    e.stopPropagation();
    const shareUrl = `${window.location.origin}/product/${product.id}`;

    try {
      await navigator.clipboard.writeText(shareUrl);
      showToast('Link copied to clipboard!', 'success');
    } catch (err) {
      // Fallback for older browsers
      uiLogger.error('Failed to copy', err);
      showToast(`Share this link: ${shareUrl}`, 'info');
    }
  };

  const handleViewDetails = () => navigate(`/product/${product.id}`);

  const commissionAmount = product.price * product.commissionRate;
  const outOfStock = product.stock <= 0;

  return (
    <div
      onClick={handleViewDetails}
      className="glass-pearl dark:glass-void rounded-2xl overflow-hidden hover-lift transition-all duration-300 group flex flex-col h-full cursor-pointer relative border border-white/40 dark:border-white/5"
    >
      {/* Image Container */}
      <div className="relative aspect-square bg-gradient-to-br from-gray-50 to-white dark:from-slate-900 dark:to-slate-800 overflow-hidden p-6 flex items-center justify-center group-hover:p-4 transition-all duration-500">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-white/80 via-transparent to-transparent dark:from-white/5 dark:via-transparent dark:to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500" />

        <img
          src={product.imageUrl}
          alt={product.name}
          loading="lazy"
          className={`w-full h-full object-contain mix-blend-multiply dark:mix-blend-normal drop-shadow-xl transition-transform duration-500 ${outOfStock ? 'grayscale opacity-50' : 'group-hover:scale-110 group-hover:-rotate-3'}`}
        />

        {/* Overlay Badge */}
        <div className="absolute top-3 right-3 bg-white/90 dark:bg-slate-900/90 backdrop-blur-md text-brand-primary dark:text-teal-400 border border-brand-primary/20 dark:border-teal-500/30 text-[10px] font-bold px-3 py-1.5 rounded-full shadow-lg flex items-center gap-1 z-10 group-hover:scale-105 transition-transform">
          {t('productcard.earn')}{new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND', maximumFractionDigits: 0 }).format(commissionAmount)}
        </div>

        {/* Hover Overlay for View Details */}
        <div className="absolute inset-0 bg-black/0 group-hover:bg-black/5 dark:group-hover:bg-black/40 transition-colors duration-300 flex items-center justify-center">
          <div className="opacity-0 group-hover:opacity-100 transition-all duration-300 bg-white/90 dark:bg-slate-900/90 backdrop-blur-xl text-brand-dark dark:text-slate-100 px-5 py-2.5 rounded-full shadow-2xl border border-white/50 dark:border-white/10 font-bold text-xs flex items-center gap-2 transform translate-y-4 group-hover:translate-y-0 hover:scale-105">
            <Eye className="w-3.5 h-3.5" /> {t('productcard.view_details')}</div>
        </div>

        {outOfStock && (
          <div className="absolute inset-0 flex items-center justify-center bg-white/60 dark:bg-black/60 backdrop-blur-[2px] z-20">
            <span className="bg-gray-900 text-white text-xs font-bold px-4 py-1.5 rounded-full shadow-xl">{t('productcard.out_of_stock')}</span>
          </div>
        )}
      </div>

      {/* Content */}
      <div className="p-5 flex flex-col flex-1 relative">
        <div className="absolute inset-0 bg-gradient-to-b from-white/0 via-white/50 to-white/80 dark:from-transparent dark:via-slate-900/50 dark:to-slate-900/80 pointer-events-none" />

        <div className="relative z-10 flex flex-col flex-1">
          <h3 className="font-bold text-gray-900 dark:text-slate-100 text-lg mb-1 leading-tight group-hover:text-brand-primary dark:group-hover:text-teal-400 transition-colors line-clamp-1" title={product.name}>
            {product.name}
          </h3>

          <div className="flex items-center justify-between mb-4">
            <span className="text-brand-primary dark:text-teal-400 font-extrabold text-xl text-glow-brand">{formatVND(product.price)}</span>
            <span className={`text-[10px] px-2.5 py-1 rounded-full font-bold border ${outOfStock ? 'bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 border-red-200 dark:border-red-800' : 'bg-teal-50 dark:bg-teal-900/20 text-teal-700 dark:text-teal-300 border-teal-200 dark:border-teal-800'}`}>
              {t('productcard.stock')}{product.stock}
            </span>
          </div>

          <p className="text-xs text-gray-600 dark:text-slate-400 mb-5 line-clamp-2 min-h-[2.5em] leading-relaxed">{product.description}</p>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-auto">
            <button
              onClick={handleShare}
              className="flex items-center justify-center gap-2 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-600 hover:border-gray-300 dark:hover:border-slate-500 text-gray-700 dark:text-slate-300 hover:bg-gray-50 dark:hover:bg-slate-700 active:bg-gray-100 dark:active:bg-slate-600 py-3 rounded-xl text-xs font-bold transition-all duration-200 hover:shadow-lg active:scale-95"
              aria-label="Share product link"
            >
              <Share2 className="w-3.5 h-3.5" /> {t('productcard.share')}</button>

            <button
              onClick={handleBuy}
              disabled={isBuying || outOfStock || showSuccess}
              className={`btn-liquid flex items-center justify-center gap-2 py-3 rounded-xl text-xs font-bold transition-all duration-200 relative
                    ${showSuccess
                  ? 'bg-green-500 dark:bg-green-600 text-white border-green-500 shadow-lg shadow-green-500/30'
                  : 'bg-brand-accent dark:bg-yellow-400 text-brand-primary dark:text-slate-900 hover:bg-yellow-400 dark:hover:bg-yellow-300 active:bg-yellow-500 dark:active:bg-yellow-400 border border-transparent shadow-lg shadow-yellow-500/20'
                }
                    ${(outOfStock || isBuying) ? 'opacity-70 cursor-not-allowed' : 'hover:shadow-xl hover:shadow-yellow-500/30 active:scale-95'}
                `}
            >
              {isBuying ? (
                <Loader2 className="w-3.5 h-3.5 animate-spin" />
              ) : showSuccess ? (
                <div className="flex items-center gap-1 animate-in fade-in zoom-in">
                  <CheckCircle className="w-3.5 h-3.5" /> {t('productcard.added')}</div>
              ) : (
                <>
                  <ShoppingBag className="w-3.5 h-3.5" /> {t('productcard.buy_now')}</>
              )}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;

import React, { useState } from 'react';
import { LayoutDashboard, ShoppingBag, Wallet, LogOut, Sparkles, Bot, CheckCircle2, Circle, Users, Share2, Trophy, Heart, Megaphone, Moon, Sun, Activity, Shield, Settings } from 'lucide-react';
import { getCoachAdvice } from '../services/geminiService';
import { motion, AnimatePresence } from 'framer-motion';
import { useStore } from '../store';
import { useNavigate, useLocation } from 'react-router-dom';
import { useTranslation } from '../hooks';
import { useTheme } from '../context/ThemeContext';
import { isAdmin as checkIsAdmin } from '@/utils/admin-check';

interface MenuItem {
  path: string;
  label: string;
  icon: React.ComponentType<{ className?: string }>;
  matches?: string[];
  badge?: string;
}

interface SidebarProps {
  onMobileClose?: () => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ onMobileClose }) => {
  const { t } = useTranslation();
  const { user, quests, logout } = useStore();
  const navigate = useNavigate();
  const location = useLocation();
  const { theme, toggleTheme } = useTheme();
  const [advice, setAdvice] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  // Check if current user is admin
  const isAdmin = checkIsAdmin(user?.email) || user?.role === 'admin' || user?.isAdmin === true;

  const menuItems: MenuItem[] = [
    { path: '/dashboard', label: t('nav.dashboard'), icon: LayoutDashboard },
    { path: '/dashboard/marketplace', label: t('nav.marketplace'), icon: ShoppingBag, matches: ['/dashboard/product'] },
    { path: '/dashboard/wallet', label: t('nav.wallet'), icon: Wallet },
    { path: '/dashboard/leaderboard', label: t('nav.leaderboard'), icon: Trophy, badge: 'HOT' },
    { path: '/dashboard/marketing-tools', label: t('nav.marketingTools'), icon: Megaphone, badge: 'NEW' },
    { path: '/dashboard/agents', label: t('nav.agentDashboard'), icon: Activity },
    { path: '/dashboard/health-check', label: t('nav.healthCheck'), icon: Heart },
    { path: '/dashboard/health-coach', label: t('nav.healthCoach'), icon: Sparkles, badge: 'AI' },
    { path: '/dashboard/copilot', label: t('nav.copilot'), icon: Bot, badge: 'AI' },
    { path: '/dashboard/team', label: t('nav.team'), icon: Users },
    { path: '/dashboard/network', label: t('nav.network'), icon: Users },
    { path: '/dashboard/withdrawal', label: t('nav.withdrawal'), icon: Wallet },
    { path: '/dashboard/referral', label: t('nav.referral'), icon: Share2 },
    { path: '/dashboard/settings', label: t('nav.settings'), icon: Settings },
    // Admin menu - only visible to admin users
    ...(isAdmin ? [{ path: '/admin', label: t('nav.admin'), icon: Shield, badge: 'ADMIN' }] : []),
  ];

  const handleNav = (path: string) => {
    navigate(path);
    if (onMobileClose) onMobileClose();
  };

  const handleLogout = async () => {
    await logout();
    navigate('/');
  };

  const handleAdvice = async () => {
    setLoading(true);
    try {
      const pending = quests.filter(q => !q.isCompleted).map(q => q.title);
      const text = await getCoachAdvice(user.name, user.totalSales, pending);
      setAdvice(text);
    } catch {
      setAdvice(t('sidebar.coachFallback'));
    }
    setLoading(false);
  };

  return (
    <aside
      className="bg-zinc-50 dark:bg-zinc-950 border-r border-zinc-200 dark:border-zinc-800 flex flex-col h-screen overflow-y-auto transition-colors"
      role="navigation"
      aria-label={t('nav.mainNavigation')}
    >
      <div
        className="p-6 flex items-center gap-3 cursor-pointer"
        onClick={() => handleNav('/dashboard')}
        role="button"
        tabIndex={0}
        onKeyDown={(e) => {
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            handleNav('/dashboard');
          }
        }}
        aria-label={t('nav.wellnexusHome')}
      >
        <div className="w-10 h-10 bg-zinc-800 dark:bg-zinc-900 rounded-xl flex items-center justify-center text-emerald-400 font-bold shadow-lg border border-zinc-200 dark:border-zinc-800 flex-shrink-0">W</div>
        <div>
          <h1 className="font-bold text-xl text-zinc-900 dark:text-zinc-100 leading-none">{t('sidebar.wellnexus')}</h1>
          <p className="text-[10px] text-zinc-500 dark:text-zinc-400 uppercase tracking-widest font-semibold mt-1">{t('sidebar.social_commerce')}</p>
        </div>
      </div>

      <nav className="flex-1 px-4 space-y-1 py-4" aria-label={t('nav.primaryNavigation')}>
        {menuItems.map((item) => {
          const Icon = item.icon;
          const isActive = location.pathname === item.path || (item.matches && item.matches.some(m => location.pathname.startsWith(m)));

          return (
            <button
              key={item.path}
              onClick={() => handleNav(item.path)}
              className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-xl text-sm font-medium transition-all duration-200 group ${isActive
                ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 border border-emerald-500/20 shadow-lg shadow-emerald-500/5'
                : 'text-zinc-500 dark:text-zinc-400 hover:bg-zinc-100 dark:hover:bg-zinc-900 hover:text-zinc-800 dark:hover:text-zinc-100'
                }`}
              aria-current={isActive ? 'page' : undefined}
              aria-label={t('nav.navigateTo', { label: item.label })}
            >
              <Icon className={`w-5 h-5 transition-colors ${isActive ? 'text-emerald-600 dark:text-emerald-400' : 'text-zinc-400 dark:text-zinc-400 group-hover:text-zinc-600 dark:group-hover:text-zinc-300'}`} aria-hidden="true" />
              <span className="flex-1 text-left">{item.label}</span>
              {item.badge && (
                <span className={`text-xs px-2 py-0.5 rounded-full font-bold ${isActive ? 'bg-emerald-500/20 text-emerald-600 dark:text-emerald-300' : 'bg-zinc-100 dark:bg-zinc-800 text-zinc-500 dark:text-zinc-400'
                  }`}>
                  {item.badge}
                </span>
              )}
            </button>
          );
        })}
      </nav>

      <div className="p-4">
        <div className="bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 rounded-2xl p-5 relative overflow-hidden shadow-xl group">
          <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/10 rounded-full blur-2xl -mr-10 -mt-10 pointer-events-none"></div>

          <div className="relative z-10">
            <div className="flex justify-between items-center mb-4">
              <div className="flex items-center gap-2 text-zinc-800 dark:text-zinc-100 font-bold text-sm">
                <Bot className="w-4 h-4 text-emerald-400" /> {t('sidebar.the_coach')}</div>
              <span className="text-[10px] font-bold bg-zinc-100 dark:bg-zinc-800 text-zinc-500 dark:text-zinc-400 px-2 py-1 rounded-full border border-zinc-200 dark:border-zinc-700">{t('sidebar.day_3_30')}</span>
            </div>

            <ul className="space-y-2 mb-4" aria-label={t('sidebar.questList')}>
              {quests.map((q) => (
                <li key={q.id} className="flex items-start gap-2 text-xs">
                  {q.isCompleted ? <CheckCircle2 className="w-4 h-4 text-emerald-500 shrink-0" aria-hidden="true" /> : <Circle className="w-4 h-4 text-zinc-600 shrink-0" aria-hidden="true" />}
                  <div className="flex-1">
                    <p className={`font-medium ${q.isCompleted ? 'text-zinc-400 line-through' : 'text-zinc-700 dark:text-zinc-300'}`}>{q.title}</p>
                  </div>
                  <span className="text-[10px] font-bold text-emerald-400 bg-emerald-500/10 px-1.5 py-0.5 rounded">+{q.xp}{t('sidebar.xp')}</span>
                </li>
              ))}
            </ul>

            <AnimatePresence mode='wait'>
              {advice ? (
                <motion.div
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  className="bg-zinc-100 dark:bg-zinc-800 rounded-lg p-3 text-xs text-zinc-600 dark:text-zinc-300 italic border border-zinc-200 dark:border-zinc-700 mb-2"
                  role="status"
                  aria-live="polite"
                >
                  "{advice}"
                </motion.div>
              ) : (
                <button
                  onClick={handleAdvice}
                  disabled={loading}
                  className="w-full py-2.5 bg-emerald-600 hover:bg-emerald-500 text-white font-bold text-xs rounded-lg flex items-center justify-center gap-2 transition-all duration-200 shadow-lg shadow-emerald-500/20 hover:shadow-emerald-500/30"
                  aria-label={loading ? t('common.loading') : t('sidebar.getAiAdviceLabel')}
                >
                  {loading ? <Sparkles className="w-3 h-3 animate-spin" aria-hidden="true" /> : <Sparkles className="w-3 h-3" aria-hidden="true" />} {t('sidebar.get_ai_advice')}</button>
              )}
            </AnimatePresence>
          </div>
        </div>
      </div>

      <div className="px-6 py-2">
        <button
          onClick={toggleTheme}
          className="w-full flex items-center justify-between px-4 py-3 rounded-xl bg-zinc-900/50 dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 hover:bg-zinc-100 dark:hover:bg-zinc-800 transition-all group"
          aria-label={theme === 'dark' ? t('nav.switchToLight') : t('nav.switchToDark')}
        >
          <div className="flex items-center gap-3">
            <div className={`p-1.5 rounded-lg ${theme === 'dark' ? 'bg-zinc-800 text-zinc-400' : 'bg-amber-100 text-amber-600'}`}>
              {theme === 'dark' ? <Moon className="w-4 h-4" /> : <Sun className="w-4 h-4" />}
            </div>
            <span className="text-sm font-medium text-zinc-600 dark:text-zinc-400 group-hover:text-zinc-900 dark:group-hover:text-zinc-200 transition-colors">
              {theme === 'dark' ? t('nav.darkMode') : t('nav.lightMode')}
            </span>
          </div>
          <div className={`w-8 h-4 rounded-full relative transition-colors ${theme === 'dark' ? 'bg-emerald-500/20' : 'bg-zinc-200'}`}>
            <div className={`absolute top-0.5 w-3 h-3 rounded-full transition-all duration-300 ${theme === 'dark' ? 'left-4.5 bg-emerald-400' : 'left-0.5 bg-white shadow-sm'}`}
              style={{ left: theme === 'dark' ? '18px' : '2px' }}
            />
          </div>
        </button>
      </div>

      <div className="p-4 border-t border-zinc-200 dark:border-zinc-800">
        <div className="flex items-center gap-3">
          <img
            src={user.avatarUrl}
            alt={`${user.name}'s profile picture`}
            loading="lazy"
            className="w-10 h-10 rounded-full border border-zinc-700 shadow-sm object-cover"
          />
          <div className="flex-1 min-w-0">
            <p className="text-sm font-bold text-zinc-900 dark:text-zinc-100 truncate">{user.name}</p>
            <p className="text-xs text-emerald-400 font-medium" aria-label={t('nav.rankLabel', { rank: user.rank })}>{user.rank}</p>
          </div>
          <button
            onClick={handleLogout}
            className="text-zinc-400 hover:text-red-400 transition p-2 rounded-full hover:bg-zinc-800"
            aria-label={t('nav.logout')}
          >
            <LogOut className="w-4 h-4" aria-hidden="true" />
          </button>
        </div>
      </div>
    </aside>
  );
};

