// ===== BENTO CARD WITH SPOTLIGHT =====

interface BentoCardProps {
    children: React.ReactNode;
    className?: string;
    colSpan?: 1 | 2 | 3;
    rowSpan?: 1 | 2;
    href?: string;
}

export const BentoCard: React.FC<BentoCardProps> = ({
    children,
    className = '',
    colSpan = 1,
    rowSpan = 1,
    href
}) => {
    const mouseX = useMotionValue(0);
    const mouseY = useMotionValue(0);

    function handleMouseMove({ currentTarget, clientX, clientY }: React.MouseEvent) {
        const { left, top } = currentTarget.getBoundingClientRect();
        mouseX.set(clientX - left);
        mouseY.set(clientY - top);
    }

    const colClasses = {
        1: 'md:col-span-1',
        2: 'md:col-span-2',
        3: 'md:col-span-3'
    };

    const rowClasses = {
        1: 'row-span-1',
        2: 'row-span-2'
    };

    const Content = (
        <div
            className={`group relative border border-white/10 bg-zinc-900/50 overflow-hidden rounded-3xl ${colClasses[colSpan]} ${rowClasses[rowSpan]} ${className}`}
            onMouseMove={handleMouseMove}
        >
            <motion.div
                className="pointer-events-none absolute -inset-px rounded-3xl opacity-0 transition duration-300 group-hover:opacity-100"
                style={{
                    background: useMotionTemplate`
            radial-gradient(
              650px circle at ${mouseX}px ${mouseY}px,
              rgba(16, 185, 129, 0.1),
              transparent 80%
            )
          `
                }}
            />
            <div className="relative h-full">
                {children}
            </div>
        </div>
    );

    if (href) {
        return <a href={href} className="block h-full">{Content}</a>;
    }

    return Content;
};

