import React, { useState, useMemo, useCallback } from 'react';
import { Search, Command, ChevronRight, X, Loader2 } from 'lucide-react';
import { AGENCYOS_COMMANDS, AgencyOSCategory } from '@/agents/custom/AgencyOSAgent';
import { agentRegistry } from '@/agents';
import { commandRateLimiter } from '@/lib/rate-limiter';
import analytics from '@/lib/analytics';
import { useTranslation } from '@/hooks';

interface CommandPaletteProps {
    isOpen: boolean;
    onClose: () => void;
}

export function CommandPalette({ isOpen, onClose }: CommandPaletteProps) {
    const { t } = useTranslation();

    const CATEGORY_ICONS: Record<AgencyOSCategory, string> = {
        marketing: '📣',
        sales: '💼',
        finance: '💰',
        operations: '⚙️',
        strategy: '🎯',
        agents: '🤖',
    };

    const CATEGORY_LABELS: Record<AgencyOSCategory, string> = {
        marketing: t('agencyos.categories.marketing'),
        sales: t('agencyos.categories.sales'),
        finance: t('agencyos.categories.finance'),
        operations: t('agencyos.categories.operations'),
        strategy: t('agencyos.categories.strategy'),
        agents: t('agencyos.categories.agents'),
    };

    const [search, setSearch] = useState('');
    const [selectedCategory, setSelectedCategory] = useState<AgencyOSCategory | null>(null);
    const [isExecuting, setIsExecuting] = useState(false);
    const [lastResult, setLastResult] = useState<{ success: boolean; message?: string; output?: string; error?: string } | null>(null);

    const filteredCommands = useMemo(() => {
        const results: Array<{ category: AgencyOSCategory; command: string; description: string; i18nKey: string }> = [];
        const lowerSearch = search.toLowerCase();

        const categories = selectedCategory
            ? [selectedCategory]
            : (Object.keys(AGENCYOS_COMMANDS) as AgencyOSCategory[]);

        for (const cat of categories) {
            for (const cmd of AGENCYOS_COMMANDS[cat]) {
                if (
                    !search ||
                    cmd.command.toLowerCase().includes(lowerSearch) ||
                    cmd.description.toLowerCase().includes(lowerSearch)
                ) {
                    results.push({ category: cat, ...cmd });
                }
            }
        }

        return results;
    }, [search, selectedCategory]);

    // Execute a command via AgencyOSAgent
    const executeCommand = useCallback(async (command: string) => {
        // Check rate limit
        const userId = 'user'; // In production, use actual user ID
        if (!commandRateLimiter.isAllowed(userId, command)) {
            const resetTime = Math.ceil(commandRateLimiter.getResetTime(userId) / 1000);
            setLastResult({
                success: false,
                error: `Rate limit exceeded. Please wait ${resetTime}s before executing more commands.`,
            });
            analytics.event('rate_limit_exceeded', { command });
            return;
        }

        setIsExecuting(true);
        setLastResult(null);
        const startTime = Date.now();

        try {
            const agent = agentRegistry.get('AgencyOS');
            if (!agent) {
                throw new Error('AgencyOS agent not found in registry');
            }

            const result = await agent.execute({
                action: 'executeCommand',
                command,
            }) as { success: boolean; message?: string; output?: string; error?: string };

            const executionTime = Date.now() - startTime;

            // Track successful command execution
            analytics.trackCommand(command, result.success, executionTime);

            setLastResult(result);
        } catch (error) {
            const executionTime = Date.now() - startTime;

            const errorResult = {
                success: false,
                error: error instanceof Error ? error.message : 'Unknown error',
            };

            // Track error
            analytics.trackCommand(command, false, executionTime);
            if (error instanceof Error) {
                analytics.trackError(error, { command });
            }

            setLastResult(errorResult);
        } finally {
            setIsExecuting(false);
        }
    }, []);

    // Handle keyboard shortcuts
    const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
        if (e.key === 'Escape') {
            onClose();
        }
    }, [onClose]);

    if (!isOpen) return null;

    return (
        <div
            className="fixed inset-0 z-50 flex items-start justify-center pt-[10vh]"
            onKeyDown={handleKeyDown}
        >
            {/* Backdrop */}
            <div
                className="absolute inset-0 bg-black/60 backdrop-blur-sm"
                onClick={onClose}
            />

            {/* Palette Container */}
            <div className="relative w-full max-w-2xl bg-gray-900 rounded-xl shadow-2xl border border-gray-700 overflow-hidden">
                {/* Header/Search */}
                <div className="flex items-center gap-3 px-4 py-3 border-b border-gray-700">
                    <Command className="w-5 h-5 text-cyan-400" />
                    <input
                        type="text"
                        placeholder={t('common.search')}
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="flex-1 bg-transparent text-white placeholder-gray-500 outline-none text-lg"
                        autoFocus
                    />
                    <button
                        onClick={onClose}
                        className="p-1 hover:bg-gray-800 rounded transition-colors"
                    >
                        <X className="w-5 h-5 text-gray-400" />
                    </button>
                </div>

                {/* Category Tabs */}
                <div className="flex items-center gap-1 px-4 py-2 border-b border-gray-800 overflow-x-auto">
                    <button
                        onClick={() => setSelectedCategory(null)}
                        className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${!selectedCategory
                            ? 'bg-cyan-500/20 text-cyan-400'
                            : 'text-gray-400 hover:bg-gray-800'
                            }`}
                    >
                        {t('commandpalette.all')}</button>
                    {(Object.keys(AGENCYOS_COMMANDS) as AgencyOSCategory[]).map((cat) => (
                        <button
                            key={cat}
                            onClick={() => setSelectedCategory(cat)}
                            className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors whitespace-nowrap ${selectedCategory === cat
                                ? 'bg-cyan-500/20 text-cyan-400'
                                : 'text-gray-400 hover:bg-gray-800'
                                }`}
                        >
                            {CATEGORY_ICONS[cat]} {CATEGORY_LABELS[cat]}
                        </button>
                    ))}
                </div>

                {/* Command List */}
                <div className="max-h-[50vh] overflow-y-auto">
                    {filteredCommands.length === 0 ? (
                        <div className="px-4 py-8 text-center text-gray-500">
                            <Search className="w-8 h-8 mx-auto mb-2 opacity-50" />
                            <p>{t('commandpalette.no_commands_found')}</p>
                        </div>
                    ) : (
                        <ul className="py-2">
                            {filteredCommands.map((cmd) => (
                                <li key={cmd.command}>
                                    <button
                                        onClick={() => executeCommand(cmd.command)}
                                        disabled={isExecuting}
                                        className="w-full flex items-center gap-3 px-4 py-2.5 hover:bg-gray-800/50 transition-colors text-left group"
                                    >
                                        <span className="text-lg">{CATEGORY_ICONS[cmd.category]}</span>
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-center gap-2">
                                                <code className="text-cyan-400 font-mono text-sm">
                                                    {cmd.command}
                                                </code>
                                                <span className="text-xs text-gray-600 bg-gray-800 px-1.5 py-0.5 rounded">
                                                    {CATEGORY_LABELS[cmd.category]}
                                                </span>
                                            </div>
                                            <p className="text-gray-400 text-sm truncate">
                                                {t(cmd.i18nKey)}
                                            </p>
                                        </div>
                                        <ChevronRight className="w-4 h-4 text-gray-600 group-hover:text-cyan-400 transition-colors" />
                                    </button>
                                </li>
                            ))}
                        </ul>
                    )}
                </div>

                {/* Result Display */}
                {(isExecuting || lastResult) && (
                    <div className="px-4 py-3 border-t border-gray-700 bg-gray-800/50">
                        {isExecuting ? (
                            <div className="flex items-center gap-2 text-cyan-400">
                                <Loader2 className="w-4 h-4 animate-spin" />
                                <span>{t('commandpalette.executing_command')}</span>
                            </div>
                        ) : lastResult?.success ? (
                            <div className="text-green-400">
                                <p className="font-medium">{lastResult.message}</p>
                                <p className="text-sm text-gray-400 mt-1">{lastResult.output}</p>
                            </div>
                        ) : (
                            <div className="text-red-400">
                                <p className="font-medium">{t('commandpalette.error')}</p>
                                <p className="text-sm">{lastResult?.error}</p>
                            </div>
                        )}
                    </div>
                )}

                {/* Footer */}
                <div className="px-4 py-2 border-t border-gray-700 bg-gray-800/30 flex items-center justify-between text-xs text-gray-500">
                    <span>{t('commandpalette.agencyos_85_commands')}</span>
                    <span>
                        <kbd className="px-1.5 py-0.5 bg-gray-700 rounded">⌘</kbd> +
                        <kbd className="px-1.5 py-0.5 bg-gray-700 rounded ml-1">K</kbd> {t('commandpalette.to_open')}</span>
                </div>
            </div>
        </div>
    );
}

export default CommandPalette;

import { render } from '@testing-library/react';
import { screen, fireEvent } from '@testing-library/dom';
import { describe, it, expect, vi } from 'vitest';
import { Modal } from './Modal';
import React from 'react';

// Mock framer-motion since it handles animations that might be tricky in tests
vi.mock('framer-motion', async () => {
  const actualReact = await import('react');
  return {
    motion: {
      div: actualReact.forwardRef(({ children, onClick, className, ...props }: React.HTMLAttributes<HTMLDivElement>, ref: React.ForwardedRef<HTMLDivElement>) => (
        <div ref={ref} className={className} onClick={onClick} {...props}>
          {children}
        </div>
      )),
    },
    AnimatePresence: ({ children }: { children: React.ReactNode }) => <>{children}</>,
  };
});

describe('Modal', () => {
  const defaultProps = {
    isOpen: true,
    onClose: vi.fn(),
    title: 'Test Modal',
    children: <div>Modal Content</div>,
  };

  it('renders when open', () => {
    render(<Modal {...defaultProps} />);
    expect(screen.getByText('Test Modal')).toBeInTheDocument();
    expect(screen.getByText('Modal Content')).toBeInTheDocument();
  });

  it('does not render when closed', () => {
    render(<Modal {...defaultProps} isOpen={false} />);
    expect(screen.queryByText('Test Modal')).not.toBeInTheDocument();
  });

  it('calls onClose when close button is clicked', () => {
    render(<Modal {...defaultProps} />);
    const closeButton = screen.getByLabelText('Close modal');
    fireEvent.click(closeButton);
    expect(defaultProps.onClose).toHaveBeenCalled();
  });

  it('renders with custom max width', () => {
    render(<Modal {...defaultProps} maxWidth="lg" />);
    // The Modal implementation puts the maxWidth class on the motion.div
    // which corresponds to the inner div in our mock.
    const modalHeader = screen.getByText('Test Modal').closest('div'); // Header div
    const modalContent = modalHeader?.parentElement; // motion.div
    expect(modalContent?.className).toContain('max-w-lg');
  });

  it('hides close button when configured', () => {
    render(<Modal {...defaultProps} showCloseButton={false} />);
    expect(screen.queryByLabelText('Close modal')).not.toBeInTheDocument();
  });

  it('forwards ref', () => {
    const ref = React.createRef<HTMLDivElement>();
    render(<Modal {...defaultProps} ref={ref} />);
    // The ref is attached to the motion.div which is the inner modal content
    expect(ref.current).toBeInstanceOf(HTMLDivElement);
    expect(ref.current).toHaveTextContent('Test Modal');
  });

  it('renders in the document body via portal', () => {
    render(<Modal {...defaultProps} />);
    const dialog = screen.getByRole('dialog');
    // Since we use createPortal(..., document.body), the modal should be a direct child of body
    // or at least not inside the testing-library container.
    expect(dialog.parentElement).toBe(document.body);
  });
});

/**
 * WellNexus Dashboard State Orchestration Hook
 * Manages live telemetry, financial stats, and activity streams.
 */

import { useState, useEffect, useMemo, useCallback } from 'react';
import { useStore } from '@/store';
import { useTranslation } from '@/hooks';
import { TranslationKey } from './useTranslation';
import {
    Coins,
    ShoppingBag,
    Award,
    TrendingDown,
    Gift,
    CheckCircle2,
    Users,
    Package,
    Crown,
    Target,
    Star,
    Zap,
    type LucideIcon
} from 'lucide-react';
import { formatVND, formatNumber } from '@/utils/format';

// Raw transaction row shape returned from Supabase/store
interface RawTransaction {
    id?: string;
    type?: string;
    status?: string;
    amount?: number;
    description?: string;
    created_at?: string;
    metadata?: {
        buyer_name?: string;
        [key: string]: string | number | boolean | undefined;
    };
}

export interface LiveActivity {
    id: string;
    type: 'reward' | 'order' | 'rank_up' | 'withdrawal' | 'referral';
    userName: string;
    message: string;
    timestamp: Date;
    icon: LucideIcon;
    color: string;
    bgColor: string;
    amount?: number;
    // Aligning types for consistency across components
    user?: string;
    detail?: string;
    location?: string;
}

const vietnameseNames = [
    'Nguyễn Văn Minh', 'Trần Thị Hương', 'Lê Quang Hải', 'Phạm Thu Hà',
    'Hoàng Minh Tuấn', 'Đỗ Thị Lan', 'Vũ Công Phượng', 'Ngô Thị Mai',
    'Bùi Văn Toàn', 'Đinh Thị Ngọc', 'Phan Văn Đức', 'Lý Thị Kim',
    'Trịnh Văn Quyết', 'Võ Thị Sáu', 'Mai Văn Thành', 'Cao Thị Loan',
    'Đặng Văn Lâm', 'Huỳnh Thị Ngân', 'Tô Văn Hùng', 'Lưu Thị Phương'
];

export function useDashboard() {
    const { t } = useTranslation();
    const { user, revenueData, products, transactions } = useStore();
    const [activities, setActivities] = useState<LiveActivity[]>([]);

    useEffect(() => {
        if (!transactions) return;

        // Map actual transactions to LiveActivity format
        const recentTxs = transactions.slice(0, 10).map((tx: RawTransaction) => {
            let icon = Coins;
            let color = 'text-gray-600';
            let bgColor = 'bg-gray-50 dark:bg-gray-900/20';
            let type: LiveActivity['type'] = 'order';

            if (tx.type === 'direct_commission' || tx.type === 'team_commission') {
                type = 'reward';
                icon = Award;
                color = 'text-yellow-600';
                bgColor = 'bg-yellow-50 dark:bg-yellow-900/20';
            } else if (tx.type === 'withdrawal') {
                type = 'withdrawal';
                icon = TrendingDown;
                color = 'text-blue-600';
                bgColor = 'bg-blue-50 dark:bg-blue-900/20';
            }

            return {
                id: tx.id || `activity-${Date.now()}-${Math.random()}`,
                type,
                userName: tx.metadata?.buyer_name || user.name || 'User',
                user: tx.metadata?.buyer_name || user.name || 'User',
                message: tx.description || t('dashboard.recentActivity.completedQuest'),
                detail: tx.description || t('dashboard.recentActivity.completedQuest'),
                timestamp: new Date(tx.created_at || Date.now()),
                icon,
                color,
                bgColor,
                amount: tx.amount,
                location: 'VN'
            };
        });

        setActivities(recentTxs);
    }, [transactions, t, user.name]);

    const walletStats = useMemo(() => ({
        total: user.shopBalance + (user.estimatedBonus || 0),
        available: user.shopBalance,
        pending: user.estimatedBonus || 0,
        teamVolume: user.teamVolume || 0
