import { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { User } from '@/types';
import { uiLogger } from '@/utils/logger';
import { useTranslation } from './useTranslation';

export function useHeroCard(user: User) {
    const { t } = useTranslation();
    const [copied, setCopied] = useState(false);
    const mountedRef = useRef(true);
    useEffect(() => () => { mountedRef.current = false; }, []);

    // Gamification Logic: Founder Club Quest
    const TARGET_VOLUME = 100000000; // 100M VND

    const progressPercent = useMemo(() => {
        const raw = (user.teamVolume / TARGET_VOLUME) * 100;
        return Math.min(raw, 100);
    }, [user.teamVolume]);

    const remaining = useMemo(() => {
        return Math.max(TARGET_VOLUME - user.teamVolume, 0);
    }, [user.teamVolume]);

    const referralLink = useMemo(() => {
        return user.referralLink || `wellnexus.vn/ref/${user.id}`;
    }, [user.referralLink, user.id]);

    const handleCopyLink = useCallback(async () => {
        try {
            await navigator.clipboard.writeText(referralLink);
            if (!mountedRef.current) return;
            setCopied(true);
            const timer = setTimeout(() => {
                if (mountedRef.current) setCopied(false);
            }, 2000);
            // Cleanup handled by mountedRef guard above — no need to return cleanup fn
            // (returning from useCallback is unused and causes TS7030)
        } catch (err) {
            uiLogger.error('Failed to copy', err);
        }
    }, [referralLink]);

    const handleShare = useCallback(async () => {
        if (navigator.share) {
            try {
                await navigator.share({
                    title: t('useHeroCard.share_title'),
                    text: t('useHeroCard.share_text'),
                    url: referralLink,
                });
            } catch (err) {
                if ((err as Error).name !== 'AbortError') {
                    handleCopyLink();
                }
            }
        } else {
            handleCopyLink();
        }
    }, [referralLink, handleCopyLink, t]);

    return {
        progressPercent,
        remaining,
        referralLink,
        copied,
        handleCopyLink,
        handleShare
    };
}

/**
 * WellNexus Authentication Hook
 * Uses react-hook-form + zod for validation and login logic.
 */

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useAuth } from './useAuth';
import { authLogger } from '@/utils/logger';
import { useTranslation } from '@/hooks';
import { isAdmin } from '@/utils/admin-check';
import { loginSchema, type LoginFormValues } from '@/lib/schemas/auth';

export const useLogin = () => {
    const [serverError, setServerError] = useState('');
    const [loading, setLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);
    const [success, setSuccess] = useState(false);
    const { t } = useTranslation();

    const { signIn } = useAuth();
    const navigate = useNavigate();

    const form = useForm<LoginFormValues>({
        resolver: zodResolver(loginSchema),
        defaultValues: {
            email: '',
            password: '',
            rememberMe: false,
        },
    });

    /**
     * Role-based navigation logic
     */
    const navigateAfterLogin = (userEmail: string) => {
        const userIsAdmin = isAdmin(userEmail);
        setSuccess(true);
        setLoading(false);

        setTimeout(() => {
            if (userIsAdmin) {
                navigate('/admin');
            } else {
                navigate('/dashboard');
            }
        }, 800);
    };

    /**
     * Handle Login Submission (called by react-hook-form after validation)
     */
    const onSubmit = async (data: LoginFormValues) => {
        setLoading(true);
        setServerError('');

        try {
            let timeoutId: ReturnType<typeof setTimeout>;
            const timeoutPromise = new Promise((_, reject) => {
                timeoutId = setTimeout(() => reject(new Error('TIMEOUT')), 30000);
            });

            const signInPromise = signIn(data.email, data.password);
            const result = await Promise.race([signInPromise, timeoutPromise]) as { error?: Error };
            clearTimeout(timeoutId!);

            if (result?.error) throw result.error;

            navigateAfterLogin(data.email);
        } catch (err: unknown) {
            const errorObj = err as Error;
            authLogger.error('Login failed', errorObj);

            let errorMessage = t('errors.invalidCredentials');

            if (errorObj.message === 'TIMEOUT') {
                errorMessage = t('errors.timeout');
            } else if (errorObj.message?.includes('fetch') || errorObj.message?.includes('network')) {
                errorMessage = t('errors.network');
            } else if (errorObj.message?.includes('Email not confirmed')) {
                errorMessage = t('errors.emailNotConfirmed');
            }

            setServerError(errorMessage);
            setLoading(false);
        }
    };

    return {
        register: form.register,
        handleSubmit: form.handleSubmit(onSubmit),
        errors: form.formState.errors,
        serverError,
        loading,
        showPassword,
        setShowPassword,
        success,
    };
};

