// --- POLICY ENGINE v3.0: DYNAMIC CONFIGURATION ---
// Policies are now fetched from the database in real-time.
// Default fallback values are provided for safety.

const DEFAULT_POLICY = {
    // Cấp bậc (Mapping ID từ 1-8 theo file CSV)
    RANKS: {
        THIEN_LONG: 1,
        PHUONG_HOANG: 2,
        DAI_SU_DIAMOND: 3,
        DAI_SU_GOLD: 4,
        DAI_SU_SILVER: 5,
        DAI_SU: 6,         // Mốc bắt đầu hưởng F1 8%
        KHOI_NGHIEP: 7,    // Mốc hưởng Max hoa hồng trực tiếp 25%
        CTV: 8             // Mốc thấp nhất 21%
    },

    // Hoa hồng bán lẻ trực tiếp (Direct Commission)
    COMMISSION_RATES: {
        CTV: 0.21,         // 21% cho CTV (Row 8)
        LEADER: 0.25       // 25% cho Khởi Nghiệp trở lên (Row 7)
    },

    // Hoa hồng quản lý F1 (Sponsor Bonus)
    F1_BONUS_RATE: 0.08, // 8% trên doanh số F1 (Áp dụng từ Đại Sứ trở lên)

    // Điều kiện thăng cấp (Rank Up)
    UPGRADE_THRESHOLD_STARTUP: 9900000, // 9.9 Triệu VND (Row 7)

    // Tỷ lệ đổi điểm (Mining Point)
    POINT_CONVERSION: 100000, // 100k VND = 1 Point

    // Admin 3.1: Dynamic Rank Upgrades (fallback to empty)
    rankUpgrades: []
};

/**
 * Fetch policy configuration from database
 * Falls back to default values if fetch fails
 */
async function fetchPolicyConfig(supabase: SupabaseClient) {
    try {
        const { data, error } = await supabase
            .from('policy_config')
            .select('value')
            .eq('key', 'global_policy')
            .single();

        if (error || !data) {
            console.warn('[PolicyEngine] Using default policy (DB fetch failed):', error);
            return DEFAULT_POLICY;
        }

        const config = data.value;

        // Map database config to POLICY structure
        return {
            RANKS: DEFAULT_POLICY.RANKS, // Ranks are static
            COMMISSION_RATES: {
                CTV: (config.beeAgentPolicy?.ctvCommission || 21) / 100,
                LEADER: (config.beeAgentPolicy?.startupCommission || 25) / 100
            },
            F1_BONUS_RATE: (config.beeAgentPolicy?.sponsorBonus || 8) / 100,
            UPGRADE_THRESHOLD_STARTUP: config.beeAgentPolicy?.rankUpThreshold || 9900000,
            POINT_CONVERSION: 100000, // Fixed
            rankUpgrades: config.rankUpgrades || [] // Admin 3.1: Dynamic rank upgrades
        };
    } catch (err) {
        console.error('[PolicyEngine] Error fetching config:', err);
        return DEFAULT_POLICY;
    }
}


serve(async (req) => {
    try {
        // SECURITY: Verify Webhook Secret (mandatory — reject if not configured)
        const secret = req.headers.get("x-webhook-secret");
        const expectedSecret = Deno.env.get("WEBHOOK_SECRET");

        if (!expectedSecret) {
            console.error("[Security] WEBHOOK_SECRET is not configured");
            return new Response("Server configuration error", { status: 500 });
        }

        if (secret !== expectedSecret) {
            console.error("[Security] Invalid Webhook Secret");
            return new Response("Unauthorized", { status: 401 });
        }

        // 1. Khởi tạo Supabase Admin Client (Bypass RLS)
        const supabase = createClient(
            Deno.env.get("SUPABASE_URL") ?? "",
            Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ?? ""
        );

        // 🆕 1.5. Fetch Dynamic Policy from Database (Policy Engine v3.0)
        const POLICY = await fetchPolicyConfig(supabase);
        console.log('[PolicyEngine] Loaded policy:', {
            CTV: POLICY.COMMISSION_RATES.CTV,
            LEADER: POLICY.COMMISSION_RATES.LEADER,
            F1: POLICY.F1_BONUS_RATE,
            UPGRADE: POLICY.UPGRADE_THRESHOLD_STARTUP
        });

        // 2. Nhận dữ liệu từ Webhook (Khi Order Status -> 'completed')
        const { record, old_record } = await req.json();

        // Chỉ chạy khi đơn hàng mới chuyển sang 'completed'
        if (record.status !== "completed" || old_record?.status === "completed") {
            return new Response("Skipped: Not a new completion", { status: 200 });
        }

        const orderId = record.id;
        const userId = record.user_id;
        const orderTotal = Number(record.total_vnd);

        // Guest orders (user_id = null) skip commission — no profile to reward
        if (!userId) {
            console.log(`[TheBee] Skipping guest order ${orderId} — no user_id`);
            return new Response(JSON.stringify({ success: true, message: "Guest order — skipped" }), {
                headers: { "Content-Type": "application/json" },
            });
        }

        // IDEMPOTENCY GUARD: Check if commission already paid for this order
        // Use .limit(1) without .single() to avoid PGRST116 when multiple rows exist
        const { data: existingCommissions } = await supabase
            .from("transactions")
            .select("id")
            .eq("user_id", userId)
            .eq("type", "direct_commission")
            .like("description", `%${orderId}%`)
            .limit(1);

        if (existingCommissions && existingCommissions.length > 0) {
            console.warn(`[TheBee] Commission already paid for order ${orderId}. Skipping duplicate.`);
            return new Response(JSON.stringify({ success: true, message: "Already processed" }), {
                headers: { "Content-Type": "application/json" },
            });
        }

        console.log(`[TheBee] Processing Order: ${orderId} - Total: ${orderTotal}`);

        // 3. Lấy thông tin người mua (Buyer) và Người bảo trợ (Sponsor)
        // Note: Using 'users' table directly or 'profiles' view if created.
        // The migration created a 'profiles' view mapping to 'users'.
        const { data: buyer, error: profileError } = await supabase
            .from("profiles")
            .select("id, role, role_id, sponsor_id") // role_id là số 1-8
            .eq("id", userId)
            .single();

        if (profileError || !buyer) {
            console.warn(`[TheBee] Buyer profile not found for user ${userId} — skipping commission`);
            return new Response(JSON.stringify({ success: true, message: "Profile not ready — skipped" }), {
                headers: { "Content-Type": "application/json" },
            });
        }

        // --- LOGIC 1: TÍNH HOA HỒNG TRỰC TIẾP (DIRECT SALES) ---
        // Rule: CTV (8) = 21%, Khởi Nghiệp (7) trở lên = 25%
        let directRate = POLICY.COMMISSION_RATES.CTV;
        // Default to CTV if role_id is missing or null
        const buyerRoleId = buyer.role_id || POLICY.RANKS.CTV;

        if (buyerRoleId <= POLICY.RANKS.KHOI_NGHIEP) {
            directRate = POLICY.COMMISSION_RATES.LEADER;
        }

        const directCommission = orderTotal * directRate;

        // Ghi nhận giao dịch hoa hồng cho chính người mua (Cashback/Discount)
        await supabase.from("transactions").insert({
            user_id: userId,
            amount: directCommission,
            type: "direct_commission", // Loại: Bán hàng trực tiếp
            description: `Hoa hồng bán lẻ ${directRate * 100}% đơn hàng ${orderId}`,
            status: "completed"
        });

        // Cộng tiền vào ví pending của Buyer
        await supabase.rpc("increment_pending_balance", {
            x_user_id: userId,
            x_amount: directCommission
        });

        // Send commission earned email (direct commission)
        try {
            const { data: userData } = await supabase
                .from('users')
                .select('email, full_name, pending_cashback')
                .eq('id', userId)
                .single();

            if (userData?.email) {
                await supabase.functions.invoke('send-email', {
                    body: {
                        to: userData.email,
                        subject: `💰 Bạn vừa nhận ${(directCommission).toLocaleString('vi-VN')} VND hoa hồng!`,
                        templateType: 'commission-earned',
                        data: {
                            userName: userData.full_name || 'Bạn',
                            commissionAmount: `${directCommission.toLocaleString('vi-VN')} VND`,
                            commissionType: 'direct',
                            orderId: orderId,
                            currentBalance: `${(userData.pending_cashback || 0).toLocaleString('vi-VN')} VND`,
                            commissionRate: `${(directRate * 100).toFixed(0)}%`
                        }
                    }
                });
                console.log(`[Email] Direct commission email sent to ${userData.email}`);
            }
        } catch (emailError) {
            console.error('[Email] Failed to send direct commission email:', emailError);
        }

        // --- LOGIC 2: TÍNH ĐIỂM THƯỞNG (NEXUS POINTS) ---
        // Rule: 100k = 1 Point
        const pointsEarned = Math.floor(orderTotal / POLICY.POINT_CONVERSION);
        if (pointsEarned > 0) {
            await supabase.from("transactions").insert({
                user_id: userId,
                amount: pointsEarned,
                type: "earn_mining",
                description: `Mining reward từ đơn hàng ${orderId}`,
                status: "completed"
            });

            // Update ví Point
            await supabase.rpc("increment_point_balance", {
                x_user_id: userId,
                x_amount: pointsEarned
            });
        }

        // --- LOGIC 3: TÍNH THƯỞNG F1 (SPONSOR BONUS) ---
        // Rule: Sponsor phải từ Đại Sứ (Rank 6) trở lên mới được 8%
        if (buyer.sponsor_id) {
            const { data: sponsor } = await supabase
                .from("profiles")
                .select("id, role_id")
                .eq("id", buyer.sponsor_id)
                .single();

            if (sponsor) {
                const sponsorRoleId = sponsor.role_id || POLICY.RANKS.CTV;
                // Kiểm tra điều kiện Rank của Sponsor (<= 6)
                if (sponsorRoleId <= POLICY.RANKS.DAI_SU) {
                    const f1Bonus = orderTotal * POLICY.F1_BONUS_RATE;

                    await supabase.from("transactions").insert({
                        user_id: sponsor.id,
                        amount: f1Bonus,
                        type: "sponsor_bonus", // Loại: Thưởng quản lý
                        description: `Thưởng 8% F1 từ đơn hàng của user ${userId}`,
                        status: "completed"
                    });

                    // Cộng tiền vào ví pending của Sponsor
                    await supabase.rpc("increment_pending_balance", {
                        x_user_id: sponsor.id,
                        x_amount: f1Bonus
                    });

                    console.log(`[Bonus] Paid ${f1Bonus} to Sponsor ${sponsor.id}`);

                    // Send F1 bonus email to sponsor
                    try {
                        const { data: sponsorData } = await supabase
                            .from('users')
                            .select('email, full_name, pending_cashback')
                            .eq('id', sponsor.id)
                            .single();

                        const { data: buyerData } = await supabase
                            .from('users')
                            .select('full_name')
                            .eq('id', userId)
                            .single();

                        if (sponsorData?.email) {
                            await supabase.functions.invoke('send-email', {
                                body: {
                                    to: sponsorData.email,
                                    subject: `🎁 Thưởng F1: ${f1Bonus.toLocaleString('vi-VN')} VND từ ${buyerData?.full_name || 'thành viên'}`,
                                    templateType: 'commission-earned',
                                    data: {
                                        userName: sponsorData.full_name || 'Bạn',
                                        commissionAmount: `${f1Bonus.toLocaleString('vi-VN')} VND`,
                                        commissionType: 'sponsor',
                                        orderId: orderId,
                                        fromUserName: buyerData?.full_name || 'Thành viên F1',
                                        currentBalance: `${(sponsorData.pending_cashback || 0).toLocaleString('vi-VN')} VND`,
                                        commissionRate: '8%'
                                    }
                                }
                            });
                            console.log(`[Email] F1 bonus email sent to ${sponsorData.email}`);
                        }
                    } catch (emailError) {
                        console.error('[Email] Failed to send F1 bonus email:', emailError);
                    }
                } else {
                    console.log(`[Bonus] Sponsor ${sponsor.id} rank ${sponsorRoleId} too low for F1 bonus (Requires <= 6)`);
                }
            }
        }


        // --- LOGIC 4: KIỂM TRA THĂNG CẤP (RANK UP) - ADMIN 3.1: DYNAMIC ---
        //Check ALL possible rank upgrades based on dynamic policy
        interface RankUpgrade {
            fromRank: number;
            name: string;
            conditions: {
                salesRequired?: number;
                teamVolumeRequired?: number;
                directDownlinesRequired?: number;
                minDownlineRank?: number;
            };
            toRank: number;
        }
        const rankUpgrades = (POLICY.rankUpgrades || []) as RankUpgrade[];

        // Find applicable upgrade for current user rank
        const applicableUpgrade = rankUpgrades.find(
            (upgrade) => upgrade.fromRank === buyerRoleId
        );

        if (applicableUpgrade) {
            console.log(`[RankUp] Checking upgrade: ${applicableUpgrade.name}`);

            // Calculate lifetime sales
            const { data: orders } = await supabase
                .from('orders')
                .select('total_vnd')
                .eq('user_id', userId)
                .eq('status', 'completed');

            const lifetimeSales = orders?.reduce((sum: number, o: { total_vnd: string | number }) => sum + Number(o.total_vnd), 0) || 0;

            // Get user's team volume
            const { data: userData } = await supabase
                .from('users')
                .select('team_volume')
                .eq('id', userId)
                .single();

            const teamVolume = userData?.team_volume || 0;

            // Count direct downlines
            const { data: downlines } = await supabase
                .from('users')
                .select('id, role_id')
                .eq('sponsor_id', userId);

            const directDownlinesCount = downlines?.length || 0;

            // Check if downlines meet minimum rank requirement
            let meetsDownlineRankRequirement = true;
            if (applicableUpgrade.conditions.minDownlineRank) {
                const qualifiedDownlines = downlines?.filter(
                    (d: { id: string; role_id: number }) => d.role_id <= applicableUpgrade.conditions.minDownlineRank!
                ) || [];
                meetsDownlineRankRequirement = qualifiedDownlines.length >= (applicableUpgrade.conditions.directDownlinesRequired || 0);
            }

            // Multi-condition check (AND logic)
            const conditions = applicableUpgrade.conditions;
            const meetsSales = !conditions.salesRequired || lifetimeSales >= conditions.salesRequired;
            const meetsTeamVolume = !conditions.teamVolumeRequired || teamVolume >= conditions.teamVolumeRequired;
            const meetsDownlines = !conditions.directDownlinesRequired || directDownlinesCount >= conditions.directDownlinesRequired;

            console.log(`[RankUp] Conditions Check:`, {
                sales: `${lifetimeSales} >= ${conditions.salesRequired || 0} (${meetsSales})`,
                teamVolume: `${teamVolume} >= ${conditions.teamVolumeRequired || 0} (${meetsTeamVolume})`,
                downlines: `${directDownlinesCount} >= ${conditions.directDownlinesRequired || 0} (${meetsDownlines})`,
                downlineRank: meetsDownlineRankRequirement
            });

            if (meetsSales && meetsTeamVolume && meetsDownlines && meetsDownlineRankRequirement) {
                // Perform upgrade
                const rankNames = {
                    7: 'Khởi Nghiệp',
                    6: 'Đại Sứ',
                    5: 'Đại Sứ Silver',
                    4: 'Đại Sứ Gold',
                    3: 'Đại Sứ Diamond',
                    2: 'Phượng Hoàng',
                    1: 'Thiên Long'
                };

                await supabase
                    .from('users')
                    .update({
                        rank: rankNames[applicableUpgrade.toRank as keyof typeof rankNames] || 'Unknown',
                        role_id: applicableUpgrade.toRank
                    })
                    .eq('id', userId);

                console.log(`[RankUp] ✅ User ${userId} upgraded: ${applicableUpgrade.name} (${buyerRoleId} → ${applicableUpgrade.toRank})`);

                // Send rank upgrade celebration email
                try {
                    const oldRankName = rankNames[buyerRoleId as keyof typeof rankNames] || 'CTV';
                    const newRankName = rankNames[applicableUpgrade.toRank as keyof typeof rankNames] || 'Unknown';

                    const { data: userEmail } = await supabase
                        .from('users')
                        .select('email, full_name')
                        .eq('id', userId)
                        .single();

                    if (userEmail?.email) {
                        const emailPayload = {
                            to: userEmail.email,
                            subject: `🎉 Chúc mừng! Bạn đã thăng hạng lên ${newRankName}!`,
                            userName: userEmail.full_name || 'Bạn',
                            oldRank: oldRankName,
                            newRank: newRankName,
                            newRankId: applicableUpgrade.toRank,
                            achievementDate: new Date().toLocaleDateString('vi-VN'),
                            newCommissionRate: applicableUpgrade.toRank <= 7 ? '25%' : '21%',
                            newBenefits: applicableUpgrade.toRank <= 6
                                ? ['Nhận 8% thưởng quản lý F1', 'Ưu tiên hỗ trợ VIP', 'Tham gia chương trình đào tạo cao cấp']
                                : ['Hoa hồng cao hơn', 'Công cụ hỗ trợ bán hàng'],
                            lifetimeSales: lifetimeSales ? `${lifetimeSales.toLocaleString('vi-VN')} VND` : undefined,
                            teamVolume: teamVolume ? `${teamVolume.toLocaleString('vi-VN')} VND` : undefined
                        };

                        await supabase.functions.invoke('send-email', {
                            body: {
                                to: emailPayload.to,
                                subject: emailPayload.subject,
                                templateType: 'rank-upgrade',
                                data: emailPayload
                            }
                        });

                        console.log(`[Email] Rank upgrade email sent to ${userEmail.email}`);
                    }
                } catch (emailError) {
                    console.error('[Email] Failed to send rank upgrade email:', emailError);
                    // Don't fail the whole request if email fails
                }
            } else {
                console.log(`[RankUp] User ${userId} not ready for upgrade yet`);
            }
        }


        return new Response(JSON.stringify({ success: true, message: "Reward processed" }), {
            headers: { "Content-Type": "application/json" },
        });

    } catch (error) {
        console.error("[TheBee Error]:", error);
        const errMsg = error instanceof Error ? error.message : String(error);
        return new Response(JSON.stringify({ error: errMsg }), { status: 500 });
    }
});

// Supabase Edge Function: The Core Agent Worker
// Deno Runtime - High Performance, Low Latency

import { createClient, SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2'

const MAX_ATTEMPTS = 3 // Dead letter: stop retrying after this many failures

Deno.serve(async (req) => {
  // SECURITY: Require internal service key — this worker must only be called by cron/pg_net
  const serviceKey = req.headers.get('x-service-key')
  const expectedServiceKey = Deno.env.get('INTERNAL_SERVICE_KEY')

  if (!expectedServiceKey) {
    console.error('[Security] INTERNAL_SERVICE_KEY not configured')
    return new Response(JSON.stringify({ error: 'Server configuration error' }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' }
    })
  }

  if (serviceKey !== expectedServiceKey) {
    console.error('[Security] Invalid service key')
    return new Response(JSON.stringify({ error: 'Unauthorized' }), {
      status: 401,
      headers: { 'Content-Type': 'application/json' }
    })
  }

  // Khởi tạo client trong request handler để đảm bảo env vars luôn được đọc đúng lúc
  const supabase = createClient(
    Deno.env.get('SUPABASE_URL') ?? '',
    Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
  )

  // 1. Worker nhận tín hiệu (Cron hoặc Webhook gọi định kỳ)
  // Trong thực tế, ta dùng pg_net hoặc cron để gọi function này mỗi giây

  // 2. Lấy 100 jobs (pending HOẶC processing quá 10 phút)
  // Tính thời điểm 10 phút trước
  const tenMinsAgo = new Date(Date.now() - 10 * 60 * 1000).toISOString()

  const { data: jobs, error } = await supabase
    .from('agent_jobs')
    .select('*')
    .or(`status.eq.pending,and(status.eq.processing,updated_at.lt.${tenMinsAgo})`)
    .lt('attempts', MAX_ATTEMPTS) // Dead letter guard: skip jobs that exceeded max retries
    .limit(100)

  if (!jobs || jobs.length === 0) {
    return new Response(JSON.stringify({ message: 'No jobs' }), { headers: { 'Content-Type': 'application/json' } })
  }

  const results = []

  // 3. Xử lý song song (Parallel Processing)
  await Promise.all(jobs.map(async (job) => {
    try {
      // Mark as processing with optimistic lock: only claim if still pending/timed-out-processing
      const { count } = await supabase
        .from('agent_jobs')
        .update({ status: 'processing', updated_at: new Date().toISOString() })
        .eq('id', job.id)
        .in('status', ['pending', 'processing']) // Atomic claim guard
        .select('id', { count: 'exact', head: true })

      if (!count || count === 0) {
        // Another worker claimed this job concurrently — skip
        return
      }

      // --- ROUTING AGENT ---
      if (job.agent_name === 'The Bee' && job.action === 'process_reward') {
        await runTheBee(job.payload, supabase)
      }
      // ---------------------

      // Mark as completed
      await supabase.from('agent_jobs').update({
        status: 'completed',
        processed_at: new Date().toISOString()
      }).eq('id', job.id)

      results.push({ id: job.id, status: 'ok' })

    } catch (err) {
      console.error(`Job ${job.id} failed:`, err)
      const newAttempts = job.attempts + 1
      const errMsg = err instanceof Error ? err.message : String(err)
      // Move to dead_letter if max attempts exceeded, else mark failed for retry
      await supabase.from('agent_jobs').update({
        status: newAttempts >= MAX_ATTEMPTS ? 'dead_letter' : 'failed',
        error_message: errMsg,
        attempts: newAttempts
      }).eq('id', job.id)
    }
  }))

  return new Response(JSON.stringify({ processed: results.length }), { headers: { 'Content-Type': 'application/json' } })
})

// --- AGENT LOGIC: THE BEE ---
interface BeePayload {
  user_id: string;
  amount: number;
  transaction_id: string;
}

async function runTheBee(payload: BeePayload, supabase: SupabaseClient) {
  const { user_id, amount, transaction_id } = payload

  // 1. Delegate Logic to Database (Bee 2.0)
  // The RPC 'distribute_reward' now handles:
  // - Looking up Bonus Revenue (DTTT) from Product
  // - Applying correct rate (21% vs 25%) based on User Rank
  // - Auto-Rank Upgrade

  const { error } = await supabase.rpc('distribute_reward', {
    p_user_id: user_id,
    p_amount: amount, // Pass full amount as fallback base
    p_source_tx: transaction_id
  })

  if (error) throw new Error(error.message ?? 'distribute_reward RPC failed')
}

import { serve } from 'https://deno.land/std@0.168.0/http/server.ts'
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2'

interface WebhookData {
  orderCode: number
  amount: number
  description: string
  accountNumber: string
  reference: string
  transactionDateTime: string
  currency: string
  paymentLinkId: string
  code: string
  desc: string
  counterAccountBankId?: string
  counterAccountBankName?: string
  counterAccountName?: string
  counterAccountNumber?: string
  virtualAccountName?: string
  virtualAccountNumber?: string
}

interface OrderItem {
  product_name: string
  quantity: number
  unit_price?: number
}

interface WebhookPayload {
  data: WebhookData
  signature: string
}

// Constant-time string comparison to prevent timing attacks
function secureCompare(a: string, b: string): boolean {
  if (a.length !== b.length) return false
  let result = 0
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i)
  }
  return result === 0
}

serve(async (req) => {
  // SECURITY: Verify Webhook Secret (mandatory for POST requests)
  const secret = req.headers.get("x-webhook-secret");
  const expectedSecret = Deno.env.get("WEBHOOK_SECRET");

  if (!expectedSecret) {
    console.error("[Security] WEBHOOK_SECRET is not configured");
    return new Response("Server configuration error", { status: 500 });
  }

  // Handle GET requests for PayOS webhook URL verification
  if (req.method === 'GET') {
    return new Response(JSON.stringify({ success: true }), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  if (secret !== expectedSecret) {
    console.error("[Security] Invalid Webhook Secret");
    return new Response("Unauthorized", { status: 401 });
  }

  const supabase = createClient(
    Deno.env.get('SUPABASE_URL') ?? '',
    Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
  )

  try {
    // 1. Parse webhook payload
    const payload: WebhookPayload = await req.json()
    const signature = payload.signature

    if (!signature) {
      await logAudit(supabase, null, 'PAYOS_WEBHOOK_FAILED', { error: 'Missing signature' }, 'failure')
      return new Response(
        JSON.stringify({ error: 'Missing signature' }),
        { status: 401, headers: { 'Content-Type': 'application/json' } }
      )
    }

    // 2. Get checksum key
    const checksumKey = Deno.env.get('PAYOS_CHECKSUM_KEY')
    if (!checksumKey) {
      console.error('PAYOS_CHECKSUM_KEY not configured')
      throw new Error('Server configuration error')
    }

    // 3. Verify webhook signature
    const sortedKeys = Object.keys(payload.data).sort()
    const signatureData = sortedKeys.map(key => `${key}=${payload.data[key as keyof WebhookData]}`).join('&')

    const encoder = new TextEncoder()
    const keyData = encoder.encode(checksumKey)
    const msgData = encoder.encode(signatureData)

    const cryptoKey = await crypto.subtle.importKey(
      'raw',
      keyData,
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['sign']
    )

    const signatureBuffer = await crypto.subtle.sign('HMAC', cryptoKey, msgData)
    const signatureArray = Array.from(new Uint8Array(signatureBuffer))
    const computedSignature = signatureArray.map(b => b.toString(16).padStart(2, '0')).join('')

    if (!secureCompare(signature, computedSignature)) {
      console.error('Signature mismatch:', { received: signature, computed: computedSignature })
      await logAudit(supabase, null, 'PAYOS_WEBHOOK_FAILED', { error: 'Invalid signature', payload }, 'failure')
      return new Response(
        JSON.stringify({ error: 'Invalid signature' }),
        { status: 401, headers: { 'Content-Type': 'application/json' } }
      )
    }

    // 4. Fetch current order to check state (Idempotency & State Machine)
    const { data: currentOrder, error: fetchError } = await supabase
      .from('orders')
      .select('id, status, user_id, order_code')
      .eq('order_code', payload.data.orderCode)
      .single()

    if (fetchError || !currentOrder) {
      console.error('Order not found:', payload.data.orderCode)
      await logAudit(supabase, null, 'PAYOS_WEBHOOK_FAILED', { error: 'Order not found', orderCode: payload.data.orderCode }, 'failure')
      return new Response(
        JSON.stringify({ error: 'Order not found' }),
        { status: 404, headers: { 'Content-Type': 'application/json' } }
      )
    }

    // Determine new status
    let newStatus = 'pending'
    if (payload.data.code === '00') {
      newStatus = 'paid'
    } else if (payload.data.code === '01') {
      newStatus = 'cancelled'
    }

    // State Machine Check
    // If order is already paid or cancelled, do not update again (Idempotency)
    if (currentOrder.status === 'paid' || currentOrder.status === 'cancelled') {
      console.log(`Order ${currentOrder.order_code} is already ${currentOrder.status}. Ignoring webhook update to ${newStatus}.`)
      await logAudit(supabase, currentOrder.user_id, 'PAYOS_WEBHOOK_IGNORED', {
        orderId: currentOrder.id,
        currentStatus: currentOrder.status,
        newStatus,
        reason: 'Order already finalized'
      }, 'info')

      return new Response(
        JSON.stringify({ success: true, status: currentOrder.status, message: 'Order already finalized' }),
        { headers: { 'Content-Type': 'application/json' } }
      )
    }

    // 5. Atomic update: only update if still in 'pending' state (prevents race condition)
    // If two webhooks fire simultaneously, only one will match the .eq('status', 'pending') filter
    const { data: updatedOrder, error: updateError } = await supabase
      .from('orders')
      .update({
        status: newStatus,
        payment_data: payload.data,
        updated_at: new Date().toISOString(),
      })
      .eq('id', currentOrder.id)
      .eq('status', 'pending') // Atomic guard: only update if still pending
      .select('id, status')
      .single()

    if (updateError || !updatedOrder) {
      // If no row was updated, order was already finalized by a concurrent request
      console.log(`Order ${currentOrder.order_code} was already finalized by concurrent request. Ignoring.`)
      return new Response(
        JSON.stringify({ success: true, status: 'already_finalized', message: 'Concurrent webhook already processed' }),
        { headers: { 'Content-Type': 'application/json' } }
      )
    }

    // Log success
    await logAudit(supabase, currentOrder.user_id, 'PAYOS_WEBHOOK_SUCCESS', {
      orderId: currentOrder.id,
      oldStatus: currentOrder.status,
      newStatus,
      amount: payload.data.amount
    }, 'success')

    // 6a. Sync to transactions table (single source of truth for business logic)
    // This ensures commission/history logic works even if frontend closes before processOrder runs
    if (newStatus === 'paid') {
      const { data: existingTx } = await supabase
        .from('transactions')
        .select('id')
        .eq('reference_id', currentOrder.id)
        .eq('type', 'sale')
        .limit(1)

      if (!existingTx || existingTx.length === 0) {
        await supabase.from('transactions').insert({
          user_id: currentOrder.user_id,
          amount: payload.data.amount,
          type: 'sale',
          status: 'completed',
          description: `PayOS đơn hàng #${payload.data.orderCode}`,
          reference_id: currentOrder.id,
          created_at: new Date().toISOString(),
        }).catch((err: Error) => console.error('Failed to sync transaction:', err))
      }
    }

    // 6. Trigger order confirmation email on successful payment
    if (newStatus === 'paid') {
      if (currentOrder.user_id) {
        // Fetch user email/name and order items for the email template
        const [userResult, itemsResult] = await Promise.all([
          supabase.from('users').select('email, full_name').eq('id', currentOrder.user_id).single(),
          supabase.from('order_items')
            .select('product_name, quantity, unit_price')
            .eq('order_id', currentOrder.id),
        ])

        const user = userResult.data
        const items = itemsResult.data || []

        if (user?.email) {
          // Fire-and-forget with explicit catch — do not block webhook response
          supabase.functions
            .invoke('send-email', {
              body: {
                to: user.email,
                subject: `✅ Đơn hàng #${payload.data.orderCode} đã được xác nhận!`,
                templateType: 'order-confirmation',
                data: {
                  userName: user.full_name || 'Bạn',
                  orderId: String(payload.data.orderCode),
                  orderDate: new Date().toLocaleDateString('vi-VN'),
                  totalAmount: `${payload.data.amount.toLocaleString('vi-VN')} VND`,
                  items: items.map((i: OrderItem) => ({
                    name: i.product_name,
                    quantity: i.quantity,
                    price: `${(i.unit_price || 0).toLocaleString('vi-VN')} VND`,
                  })),
                },
              },
            })
            .catch((err) => console.error('Email send failed:', err))
        }
      }

      // 7. Trigger commission distribution via agent-reward
      if (currentOrder.user_id) {
        const webhookSecret = Deno.env.get('WEBHOOK_SECRET')
        supabase.functions
          .invoke('agent-reward', {
            body: {
              record: {
                id: currentOrder.id,
                user_id: currentOrder.user_id,
                total_vnd: payload.data.amount,
                status: 'completed',
              },
              old_record: { status: 'pending' },
            },
            ...(webhookSecret ? { headers: { 'x-webhook-secret': webhookSecret } } : {}),
          })
          .then(() => console.log(`Commission distributed for order ${currentOrder.id}`))
          .catch((err) => console.error('Commission distribution failed:', err))
      }
    }

    return new Response(
      JSON.stringify({ success: true, status: newStatus }),
      { headers: { 'Content-Type': 'application/json' } }
    )

  } catch (error) {
    console.error('Webhook processing error:', error)
    return new Response(
      JSON.stringify({ error: error instanceof Error ? error.message : 'Unknown error' }),
      { status: 500, headers: { 'Content-Type': 'application/json' } }
    )
  }
})

// Helper to log to audit_logs table
async function logAudit(supabase: ReturnType<typeof createClient>, userId: string | null, action: string, payload: Record<string, unknown>, severity: string) {
  try {
    // If we don't have a user_id (e.g. failed signature), we might log with a system user or just null
    // Assuming audit_logs table allows null user_id or we use a specific system UUID if needed.
    // Based on migration, user_id is nullable? Let's check migration again.
    // Migration: user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE
    // It does not say NOT NULL, so it should be nullable.

    await supabase.from('audit_logs').insert({
      user_id: userId,
      action: action,
      payload: { ...payload, severity },
      user_agent: 'PayOS-Webhook-Service',
      ip_address: '0.0.0.0' // We don't have easy access to IP in this context without specific headers
    })
  } catch (err) {
    console.error('Failed to write audit log:', err)
    // Don't block the webhook response for audit logging failure
  }
}

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
import { generateWelcomeEmail } from "./templates/welcome-email-template.ts";
import { generateOrderConfirmationEmail } from "./templates/order-confirmation-email-template.ts";
import { generateCommissionEarnedEmail } from "./templates/commission-earned-email-template.ts";
import { generateRankUpgradeEmail } from "./templates/rank-upgrade-celebration-email-template.ts";
import { generateWithdrawalApprovedEmail } from "./templates/withdrawal-approved-email-template.ts";
import { generateWithdrawalRejectedEmail } from "./templates/withdrawal-rejected-email-template.ts";
import { generateWithdrawalPendingEmail } from "./templates/withdrawal-pending-email-template.ts";

// Resend API endpoint
const RESEND_API_ENDPOINT = "https://api.resend.com/emails";

const ALLOWED_ORIGINS = [
  'https://wellnexus.vn',
  'https://www.wellnexus.vn',
];

function getCorsHeaders(req: Request): Record<string, string> {
  const origin = req.headers.get('Origin') ?? '';
  const allowedOrigin = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
  return {
    'Access-Control-Allow-Origin': allowedOrigin,
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
    'Vary': 'Origin',
  };
}

interface EmailRequest {
  to: string | string[];
  subject: string;
  html?: string; // Optional if using template
  templateType?: 'welcome' | 'order-confirmation' | 'commission-earned' | 'rank-upgrade' | 'withdrawal-approved' | 'withdrawal-rejected' | 'withdrawal-pending';
  data?: Record<string, unknown>;
  from?: string;
  replyTo?: string;
}

serve(async (req) => {
  const corsHeaders = getCorsHeaders(req);

  // Handle CORS preflight
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders });
  }

  // Require service role key OR authenticated user (internal calls only)
  const authHeader = req.headers.get('Authorization');
  const serviceKey = req.headers.get('x-service-key');
  const expectedServiceKey = Deno.env.get('INTERNAL_SERVICE_KEY');

  // Allow if valid service key (internal server-to-server call)
  const hasValidServiceKey = expectedServiceKey && serviceKey === expectedServiceKey;

  // Allow if authenticated Supabase user (logged-in user triggering email)
  let isAuthenticatedUser = false;
  if (!hasValidServiceKey && authHeader) {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_ANON_KEY') ?? '',
      { global: { headers: { Authorization: authHeader } } }
    );
    const { data: { user } } = await supabase.auth.getUser();
    isAuthenticatedUser = !!user;
  }

  if (!hasValidServiceKey && !isAuthenticatedUser) {
    return new Response(
      JSON.stringify({ error: 'Unauthorized' }),
      { status: 401, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
    );
  }

  try {
    const { to, subject, html, templateType, data, from, replyTo }: EmailRequest = await req.json();

    // Validate required fields
    if (!to || !subject) {
      return new Response(
        JSON.stringify({ error: 'Missing required fields: to, subject' }),
        { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    // Generate HTML from template if templateType is provided
    let emailHtml = html;
    if (!emailHtml && templateType && data) {
      switch (templateType) {
        case 'welcome':
          emailHtml = generateWelcomeEmail(data);
          break;
        case 'order-confirmation':
          emailHtml = generateOrderConfirmationEmail(data);
          break;
        case 'commission-earned':
          emailHtml = generateCommissionEarnedEmail(data);
          break;
        case 'rank-upgrade':
          emailHtml = generateRankUpgradeEmail(data);
          break;
        case 'withdrawal-approved':
          emailHtml = generateWithdrawalApprovedEmail(data);
          break;
        case 'withdrawal-rejected':
          emailHtml = generateWithdrawalRejectedEmail(data);
          break;
        case 'withdrawal-pending':
          emailHtml = generateWithdrawalPendingEmail(data);
          break;
        default:
          return new Response(
            JSON.stringify({ error: `Unknown template type: ${templateType}` }),
            { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
          );
      }
    }

    // Validate we have HTML content
    if (!emailHtml) {
      return new Response(
        JSON.stringify({ error: 'Missing email content: provide either html or templateType with data' }),
        { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    // Get Resend API key from environment
    const resendApiKey = Deno.env.get('RESEND_API_KEY');
    if (!resendApiKey) {
      console.error('[SendEmail] RESEND_API_KEY not configured');
      return new Response(
        JSON.stringify({ error: 'Email service not configured' }),
        { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    // Send email via Resend API
    const emailPayload = {
      from: from || 'WellNexus <noreply@wellnexus.vn>',
      to: Array.isArray(to) ? to : [to],
      subject,
      html: emailHtml,
      ...(replyTo && { reply_to: replyTo }),
    };

    console.log('[SendEmail] Sending email to:', to, 'Template:', templateType || 'custom');

    const response = await fetch(RESEND_API_ENDPOINT, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${resendApiKey}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(emailPayload),
    });

    const responseData = await response.json();

    if (!response.ok) {
      console.error('[SendEmail] Resend API error:', responseData);
      return new Response(
        JSON.stringify({
          error: 'Failed to send email',
          details: responseData
        }),
        { status: response.status, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    console.log('[SendEmail] Email sent successfully:', responseData.id);

    return new Response(
      JSON.stringify({
        success: true,
        id: responseData.id,
        message: 'Email sent successfully'
      }),
      { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
    );

  } catch (error) {
    console.error('[SendEmail] Error:', error);
    return new Response(
      JSON.stringify({
        error: 'Internal server error',
        message: error instanceof Error ? error.message : 'Unknown error'
      }),
      { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
    );
  }
});
